#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(long long*)a - *(long long*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int K, Q;
        scanf("%d %d", &K, &Q);
        long long A[K], B[K], sums[K * K];
        for (int i = 0; i < K; i++) {
            scanf("%lld", &A[i]);
        }
        for (int i = 0; i < K; i++) {
            scanf("%lld", &B[i]);
        }
        int index = 0;
        for (int i = 0; i < K; i++) {
            for (int j = 0; j < K; j++) {
                sums[index++] = A[i] + B[j];
            }
        }
        qsort(sums, K * K, sizeof(long long), compare);
        for (int i = 0; i < Q; i++) {
            int qi;
            scanf("%d", &qi);
            printf("%lld\n", sums[qi - 1]);
        }
    }
    return 0;
}

