import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int K = sc.nextInt();
            int Q = sc.nextInt();
            long[] A = new long[K];
            long[] B = new long[K];
            long[] sums = new long[K * K];
            for (int i = 0; i < K; i++) {
                A[i] = sc.nextLong();
            }
            for (int i = 0; i < K; i++) {
                B[i] = sc.nextLong();
            }
            int index = 0;
            for (int i = 0; i < K; i++) {
                for (int j = 0; j < K; j++) {
                    sums[index++] = A[i] + B[j];
                }
            }
            Arrays.sort(sums);
            for (int i = 0; i < Q; i++) {
                int qi = sc.nextInt();
                System.out.println(sums[qi - 1]);
            }
        }
    }
}

